import ast, csv, json
from pathlib import Path

limits = {
    'T1': {'meals': 200, 'hotel': 500, 'transport': 200},
    'T2': {'meals': 150, 'hotel': 350, 'transport': 150},
    'T3': {'meals': 100, 'hotel': 250, 'transport': 100},
}
t1 = {'北京', '上海', '广州', '深圳'}
t2 = {'杭州', '成都', '武汉', '南京', '西安'}

def tier(city):
    if city in t1:
        return 'T1'
    if city in t2:
        return 'T2'
    return 'T3'

def level(amount, result):
    if result == 'REJECT':
        return 'N/A'
    if amount <= 5000:
        return 'auto'
    if amount <= 20000:
        return 'manager'
    return 'director'

rows = []
with Path('input.csv').open(newline='', encoding='utf-8') as f:
    for row in csv.DictReader(f):
        days = int(row['days'])
        client_facing = row['client_facing'] == 'True'
        items = ast.literal_eval(row['items'])

        if days > 14:
            result = 'REJECT'
            approved = 0
        else:
            approved = 0
            approved_count = 0
            rejected_count = 0
            city_limits = limits[tier(row['city'])]

            for item in items:
                category = item['category']
                amount = item['amount']
                has_receipt = item['has_receipt']

                item_approved = 0
                if amount > 200 and not has_receipt:
                    rejected_count += 1
                elif category == 'entertainment':
                    if client_facing:
                        item_approved = amount
                        approved_count += 1
                    else:
                        rejected_count += 1
                elif category in city_limits:
                    item_approved = min(amount, city_limits[category] * days)
                    approved_count += 1
                else:
                    rejected_count += 1

                approved += item_approved

            if approved_count == 0:
                result = 'REJECT'
                approved = 0
            elif rejected_count == 0:
                result = 'APPROVE'
            else:
                result = 'PARTIAL'

        rows.append({
            'id': row['id'],
            'result': result,
            'approved_amount': approved,
            'approval_level': level(approved, result),
        })

Path('output.json').write_text(json.dumps(rows, ensure_ascii=False, indent=2) + '\\n', encoding='utf-8')
PY
